class Solution:
    def shipWithinDays(self, weights: List[int], days: int) -> int:
        def can_ship(capacity):
            day_count = 1
            current_load = 0
            for weight in weights:
                if current_load + weight > capacity:
                    day_count += 1
                    current_load = weight
                else:
                    current_load += weight
            return day_count <= days

        left, right = max(weights), sum(weights)
        while left < right:
            mid = (left + right) // 2
            if can_ship(mid):
                right = mid
            else:
                left = mid + 1
        return left
